const express = require('express');
const crypto = require('crypto');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');
const jwt = require('jsonwebtoken');
const { v4: uuidv4 } = require('uuid');

const app = express();
app.use(helmet());
app.use(express.json());

const SECRET_KEY = process.env.JWT_SECRET || crypto.randomBytes(32).toString('hex');
const MAX_LEVELS_PER_HOUR = 100;
const MAX_REWARDS_PER_HOUR = 50;

const levelValidator = (levelData) => {
  if (!levelData || typeof levelData !== 'object') return false;
  if (typeof levelData.levelId !== 'string' || levelData.levelId.length > 50) return false;
  if (typeof levelData.score !== 'number' || levelData.score < 0) return false;
  if (typeof levelData.time !== 'number' || levelData.time < 0) return false;
  if (typeof levelData.deviceId !== 'string' || levelData.deviceId.length > 100) return false;
  return true;
};

const rewardCalculator = (levelData) => {
  const { score, time } = levelData;
  const baseReward = Math.floor(score / 100);
  const timeBonus = Math.max(0, Math.floor((1000 - time) / 10));
  const totalReward = baseReward + timeBonus;
  
  const rewards = [];
  if (totalReward >= 100) rewards.push({ type: 'coins', amount: 50 });
  if (totalReward >= 200) rewards.push({ type: 'gems', amount: 10 });
  if (totalReward >= 500) rewards.push({ type: 'special_item', amount: 1 });
  
  return rewards;
};

const createRateLimiter = (maxRequests, windowMs) => {
  return rateLimit({
    windowMs,
    max: maxRequests,
    message: { error: 'Too many requests' },
    standardHeaders: true,
    legacyHeaders: false,
  });
};

const levelLimiter = createRateLimiter(MAX_LEVELS_PER_HOUR, 60 * 60 * 1000);
const rewardLimiter = createRateLimiter(MAX_REWARDS_PER_HOUR, 60 * 60 * 1000);

const authenticateToken = (req, res, next) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];
  
  if (!token) {
    return res.status(401).json({ error: 'Access token required' });
  }
  
  jwt.verify(token, SECRET_KEY, (err, user) => {
    if (err) {
      return res.status(403).json({ error: 'Invalid token' });
    }
    req.user = user;
    next();
  });
};

app.post('/level-complete', authenticateToken, levelLimiter, (req, res) => {
  try {
    if (!levelValidator(req.body)) {
      return res.status(400).json({ error: 'Invalid level data' });
    }
    
    const { levelId, score, time, deviceId } = req.body;
    
    const levelData = {
      levelId,
      score,
      time,
      deviceId,
      timestamp: Date.now(),
      userId: req.user.userId
    };
    
    const rewards = rewardCalculator(levelData);
    
    const completionId = uuidv4();
    
    const response = {
      completionId,
      rewards,
      totalReward: rewards.reduce((sum, r) => sum + r.amount, 0),
      timestamp: Date.now()
    };
    
    res.json(response);
  } catch (error) {
    console.error('Level completion error:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

app.post('/claim-reward', authenticateToken, rewardLimiter, (req, res) => {
  try {
    const { completionId, rewardType } = req.body;
    
    if (!completionId || !rewardType) {
      return res.status(400).json({ error: 'Missing required fields' });
    }
    
    const token = jwt.sign(
      { completionId, rewardType, userId: req.user.userId },
      SECRET_KEY,
      { expiresIn: '1h' }
    );
    
    res.json({ token });
  } catch (error) {
    console.error('Reward claim error:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

app.get('/health', (req, res) => {
  res.json({ status: 'OK', timestamp: Date.now() });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Game API server running on port ${PORT}`);
});